import React, { Component, createRef } from 'react';
import { NavLink, Link, withRouter } from 'react-router-dom';
import { connect } from 'react-redux';
import PropTypes from 'prop-types';
import s from './AppLayout.module.scss';
import $ from 'jquery';

class AppLayout extends Component {

    constructor(props) {
        super(props);
        this.state = {

        };

        this.changeUnderlinePosition = this.changeUnderlinePosition.bind();
        this.changeAccountUnderLinePosition = this.changeAccountUnderLinePosition.bind();
    }

    componentDidMount() {

    }

    componentDidUpdate() {
        if (window.location.href.indexOf("account") > -1) {
            $('.mn-nav').addClass('mn-nav--with-shadow');
        } else {
            $('.mn-nav').removeClass('mn-nav--with-shadow');
        }

        this.updateUnderlinePosition();
        this.updateAccountUnderlinePosition();
    }

    render() {

        return (
            <>
            <nav className={s.nav}>
                <div className={s['nav__inner']}>
                    <div className={s['nav-logo']}>
                        <h3><Link to="/">#DrużynaKopernika</Link></h3>
                    </div>
                    <div className={s['nav-list']}>
                        <ul>
                            {/* <li>Nasze prace</li>
                            <li>Aktualności</li>
                            <li>Wydarzenia</li>
                            <li>O nas</li>
                            <li>Kontakt</li> */}
                            <li><NavLink to="/feed" activeClassName='mn-nav--right--wrapper--active' onClick={this.animateTransition.bind(this)}>Nasze prace</NavLink></li>
                            <li><NavLink to="/share" activeClassName='mn-nav--right--wrapper--active' onClick={this.animateTransition.bind(this)}>Aktualności</NavLink></li>
                            <hr id="nav_slide_click"/>
                        </ul>
                    </div>
                </div>
            </nav>
            <div className={s.container}>
                <aside className={[s.menu, s.sticky].join(' ')}>
                <br/><br/><br/><br/><br/>
                    Aktualnosci
                </aside>
                <main className={s.feed}>
                    <div className={s['feed-wrapper']}>
                        <br/><br/><br/><br/><br/><br/>
                        Posty / Z wszystkich kategorii 
                    </div>
                </main>
                <div className={[s.sidebar, s.sticky].join(' ')}>
                    <br/><br/><br/><br/><br/><br/>
                    Jakies inne linki
                </div>
            </div>
            </>
        )
    }
}

AppLayout.propTypes = {
    auth: PropTypes.object,
};

const mapStateToProps = (state) => ({
    auth: state.auth,
});

export default withRouter(connect(mapStateToProps)(AppLayout));
